Based on the reference materials and detailed specifications, here's the complete implementation for the `delete_inactive_users` function:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return -1; // Connection failed
  }
  auto conn = *conn_result;

  // Begin transaction
  auto begin_result = sqlgen::begin_transaction(conn);
  if (!begin_result) {
    return -1; // Transaction begin failed
  }

  // Delete users with last_login before 2025-01-01
  auto delete_result = (sqlgen::delete_from<User> | sqlgen::where("last_login"_c < "2025-01-01"))(conn);
  if (!delete_result) {
    // Rollback on delete failure
    sqlgen::rollback(conn);
    return -1;
  }

  // Commit the transaction
  auto commit_result = sqlgen::commit(conn);
  if (!commit_result) {
    // Rollback on commit failure
    sqlgen::rollback(conn);
    return -1;
  }

  return 0; // Success
}

} // namespace delete_inactive_users
```

