#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = conn_result.value();

  // 2. Begin a transaction
  auto begin_result = sqlgen::begin_transaction(conn);
  if (!begin_result) {
    return false;
  }

  try {
    // 3. Read the sender's account to verify sufficient funds
    auto sender_result = (sqlgen::read<std::vector<Account>> | 
                         sqlgen::where("account_id"_c == from_account_id))(conn);

    if (!sender_result || sender_result.value().empty()) {
      sqlgen::rollback(conn);
      return false;
    }

    auto sender_balance = sender_result.value()[0].balance;
    if (sender_balance < amount) {
      sqlgen::rollback(conn);
      return false;
    }

    // 4. Update sender's balance (deduct amount)
    auto update_sender = sqlgen::update<Account>("balance"_c.set("balance"_c - amount)) 
                       | sqlgen::where("account_id"_c == from_account_id);
    auto update_sender_result = update_sender(conn);
    if (!update_sender_result) {
      sqlgen::rollback(conn);
      return false;
    }

    // 5. Update receiver's balance (add amount)
    auto update_receiver = sqlgen::update<Account>("balance"_c.set("balance"_c + amount)) 
                         | sqlgen::where("account_id"_c == to_account_id);
    auto update_receiver_result = update_receiver(conn);
    if (!update_receiver_result) {
      sqlgen::rollback(conn);
      return false;
    }

    // 6. Commit the transaction
    auto commit_result = sqlgen::commit(conn);
    if (!commit_result) {
      sqlgen::rollback(conn);
      return false;
    }

    return true;

  } catch (...) {
    // 7. Rollback on any exception
    sqlgen::rollback(conn);
    return false;
  }
}

}  // namespace transaction_transfer_funds
```

