    // Unit cost: total / quantity
    (("unit_price"_c * "quantity"_c) / "quantity"_c).as<"unit_cost">,

    // Quantity group: quantity % 10
    ("quantity"_c % 10).as<"quantity_group">,

    // Estimated profit: unit_price * 0.3
    ("unit_price"_c * 0.3).as<"estimated_profit">
  );

  // Execute the query and convert results to OrderMetrics
  auto result = query(conn);

  // Map the results to OrderMetrics struct
